// Flatten all nodes with global id
let _globalId = 0;
const ALL_NODES = LAYERS.flatMap((layer) =>
  layer.nodes.map((n) => ({
    ...n,
    pos: [layer.x, n.y, n.z],
    color: layer.color,
    layerId: layer.id,
    gid: _globalId++,
  }))
);

// Build edges: each node in layer i connects to 2-3 nodes in layer i+1
function buildEdges() {
  const edges = [];
  for (let li = 0; li < LAYERS.length - 1; li++) {
    const fromNodes = ALL_NODES.filter((n) => n.layerId === li);
    const toNodes   = ALL_NODES.filter((n) => n.layerId === li + 1);
    fromNodes.forEach((from, fi) => {
      // Connect to 2 neighbouring nodes in next layer
      const spread = toNodes.length;
      const center = (fi / (fromNodes.length - 1 || 1)) * (spread - 1);
      const picks = new Set([
        Math.round(center),
        Math.round(center + 0.5) % spread,
        (Math.round(center - 0.5) + spread) % spread,
      ]);
      picks.forEach((ti) => edges.push({ from, to: toNodes[ti] }));
    });
  }
  return edges;
}

const EDGES = buildEdges();
// Most edges carry a signal particle for density
const SIGNAL_EDGES = EDGES.filter((_, i) => i % 3 !== 2);

/* ── Glowing node with idle float ── */
function SkillNode({ pos, color, r = 0.11 }) {
  const groupRef = useRef();
  const basePos = useRef(new THREE.Vector3(...pos));
  const phase = useRef(Math.random() * Math.PI * 2);
  const floatPhase = useRef(Math.random() * Math.PI * 2);
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    const t = clock.elapsedTime;
    // Idle float — subtle bobbing on Y and Z
    groupRef.current.position.set(
      basePos.current.x,
      basePos.current.y + Math.sin(t * 0.9 + floatPhase.current) * 0.06,
      basePos.current.z + Math.cos(t * 0.7 + floatPhase.current) * 0.04,
    );
    // Pulse scale
    const s = 1 + Math.sin(t * 2.0 + phase.current) * 0.1;
    groupRef.current.scale.setScalar(s);
  });
  return (
    <group ref={groupRef} position={pos}>
      <mesh>
        <sphereGeometry args={[r, 14, 14]} />
        <meshBasicMaterial color={color} />
      </mesh>
      <mesh>
        <sphereGeometry args={[r * 2, 14, 14]} />
        <meshBasicMaterial color={color} transparent opacity={0.15}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
      <mesh>
        <sphereGeometry args={[r * 3.8, 14, 14]} />
        <meshBasicMaterial color={color} transparent opacity={0.05}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
    </group>
  );
}

/* ── Edge line ── */
function EdgeLine({ from, to }) {
  const phase = useRef(Math.random() * Math.PI * 2);
  const ref = useRef();
  const points = useMemo(() => [
    new THREE.Vector3(...from.pos),
    new THREE.Vector3(...to.pos),
  ], [from, to]);
  useFrame(({ clock }) => {
    if (!ref.current?.material) return;
    ref.current.material.opacity = 0.09 + Math.sin(clock.elapsedTime * 0.9 + phase.current) * 0.05;
  });
  return (
    <Line ref={ref} points={points}
      color={to.color} lineWidth={0.9} transparent opacity={0.09} />
  );
}

/* ── Signal particle ── */
function SignalParticle({ edge, speed, offset }) {
  const ref = useRef();
  const t = useRef(offset % 1);
  const curve = useMemo(() => {
    const a = new THREE.Vector3(...edge.from.pos);
    const b = new THREE.Vector3(...edge.to.pos);
    const mid = new THREE.Vector3().addVectors(a, b).multiplyScalar(0.5)
      .add(new THREE.Vector3(0, 0.15, 0.1));
    return new THREE.CatmullRomCurve3([a, mid, b]);
  }, [edge]);
  useFrame((_, delta) => {
    if (!ref.current) return;
    t.current = (t.current + delta * speed) % 1;
    ref.current.position.copy(curve.getPoint(t.current));
  });
  return (
    <group ref={ref}>
      <mesh>
        <sphereGeometry args={[0.055, 8, 8]} />
        <meshBasicMaterial color={edge.to.color} />
      </mesh>
      <mesh>
        <sphereGeometry args={[0.13, 8, 8]} />
        <meshBasicMaterial color={edge.to.color} transparent opacity={0.22}
          blending={THREE.AdditiveBlending} depthWrite={false} />
      </mesh>
    </group>
  );
}

/* ── Background star field ── */
function BgStars() {
  const geo = useMemo(() => {
    const COUNT = 600;
    const pos = new Float32Array(COUNT * 3);
    for (let i = 0; i < COUNT; i++) {
      pos[i * 3]     = (Math.random() - 0.5) * 18;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 10;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 6 - 3;
    }
    const g = new THREE.BufferGeometry();
    g.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    return g;
  }, []);
  return (
    <points geometry={geo}>
      <pointsMaterial color="#8899bb" size={0.012} transparent opacity={0.28} sizeAttenuation />
    </points>
  );
}

/* ── Full scene (slow sway) ── */
function NetworkScene() {
  const groupRef = useRef();
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    groupRef.current.rotation.y = Math.sin(clock.elapsedTime * 0.13) * 0.22;
    groupRef.current.rotation.x = Math.sin(clock.elapsedTime * 0.09) * 0.05;
  });
  return (
    <group ref={groupRef}>
      <BgStars />
      {EDGES.map((e, i) => <EdgeLine key={i} from={e.from} to={e.to} />)}
      {ALL_NODES.map((n) => <SkillNode key={n.gid} pos={n.pos} color={n.color} r={n.r} />)}
      {SIGNAL_EDGES.map((e, i) => (
        <SignalParticle key={i} edge={e}
          speed={0.25 + (i % 5) * 0.06} offset={i * 0.17} />
      ))}
    </group>
  );
}

/* ── Lazy-mount wrapper ── */
function LazyCanvas({ children, ...props }) {
  const wrapRef = useRef();
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (wrapRef.current) obs.observe(wrapRef.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={wrapRef} style={{ width: "100%", height: "100%" }}>
      {visible && <Canvas {...props}>{children}</Canvas>}
    </div>
  );
}

const SkillConstellation = () => (
  <div className="constellation-wrap">
    <div className="constellation-canvas" aria-hidden="true">
      <LazyCanvas
        camera={{ position: [0, 0, 7], fov: 55 }}
        gl={{ antialias: true, alpha: false }}
        onCreated={({ gl }) => gl.setClearColor("#010108", 1)}
      >
        <NetworkScene />
      </LazyCanvas>
    </div>
    <div className="constellation-legend">
      {LAYERS.map((l) => (
        <div key={l.id} className="constellation-legend-item">
          <span className="constellation-dot" style={{ background: l.color }} />
          {l.label}
        </div>
      ))}
    </div>
  </div>
);

export default SkillConstellation;
